import "./index.css";
import usefetch from './fetchdata.js'; // your custom hook
import { Link, Links } from "react-router-dom";

const Homepage = () => {
  const tasks = usefetch() || []; // fetch tasks

  if (!tasks) return <p>Loading tasks...</p>;

  return (
    <div className="homepage">
      {/* To Do Tasks */}
      <div className="yts">
        <Link to="taskname/yettostart"></Link>
       <h5>To Do Task's</h5>
        {tasks
          .filter((task) => task.Taskstatus === "Yet to start")
          .map((task) => (
            <div className="status" key={task.id}>
              <Link to={`taskname/yettostart/${task.id}`}>
              <p>{task.TaskName}</p>
              </Link>
            </div>
          ))}
          
      </div>

      <div className="inprogress">
        <h5>In Progress</h5>
        {tasks
          .filter((task) => task.Taskstatus === "In progress")
          .map((task) => (
            <div className="status" key={task.id}>
              <Link to={`taskname/in_progress/${task.id}`}>
              <p>{task.TaskName}</p>
              </Link>
            </div>
          ))}
      </div>

      <div className="Completed">
        <h5>Completed</h5>
        {tasks
          .filter((task) => task.Taskstatus === "Completed")
          .map((task) => (
            <div className="status" key={task.id}>
              <Link to={`taskname/complete/${task.id}`}>
              <p>{task.TaskName}</p>
              </Link>
            </div>
          ))}
      </div>
    </div>
  );
};

export default Homepage;
